-- ------------------------------------------------------------------------------------------------------------ --
-- 명칭 : card
-- 작성 : 2026.07.13 trisakion
-- 내용 : 유저 보유 카드 (캐릭터/아이템 겸용, 보유 인스턴스 단위)
-- ------------------------------------------------------------------------------------------------------------ --
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `card`;
CREATE TABLE `card` (
  `card_id`					BIGINT		UNSIGNED	NOT NULL	AUTO_INCREMENT												COMMENT '카드 ID',
  `user_id`					BIGINT		UNSIGNED	NOT NULL														COMMENT '유저 ID',
  `card_type`				TINYINT		UNSIGNED	NOT NULL														COMMENT '카드 종류 (1:캐릭터, 2:아이템)',
  `card_code`				VARCHAR(50)			NOT NULL														COMMENT '카드 코드 (예: CHAR_001, ITEM_001)',
  `quantity`				INT			UNSIGNED	NOT NULL	DEFAULT 1											COMMENT '보유 수량 (아이템은 중첩 가능, 캐릭터는 보통 1)',
  `acquired_at`				DATETIME				NOT NULL	DEFAULT CURRENT_TIMESTAMP								COMMENT '최초 획득일시',
  `updated_at`				DATETIME				NOT NULL	DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP	COMMENT '수정일시',
  PRIMARY KEY (`card_id`),
  UNIQUE KEY `uk_card_user_code` (`user_id`, `card_code`),
  KEY `ix_card_user_id` (`user_id`),
  CONSTRAINT `fk_card_user_id` FOREIGN KEY (`user_id`) REFERENCES `user` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='유저 보유 카드';
SET FOREIGN_KEY_CHECKS = 1;
